import React from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Alert,
} from 'react-native';
import { useAuth } from '../context/AuthContext';

export default function HomeScreen() {
  const { logout, getSessionToken } = useAuth();

  const handleLogout = () => {
    Alert.alert('Sign Out', 'Are you sure you want to sign out?', [
      { text: 'Cancel', style: 'cancel' },
      {
        text: 'Sign Out',
        style: 'destructive',
        onPress: logout,
      },
    ]);
  };

  const handleFetchProtectedData = async () => {
    const token = getSessionToken();
    try {
      const response = await fetch('https://api.myapp.com/protected/data', {
        headers: {
          'Authorization': `Bearer ${token}`,
        },
      });

      if (response.status === 401) {
        // Token expired or invalid, force logout
        Alert.alert('Session Expired', 'Please sign in again.');
        await logout();
        return;
      }

      const data = await response.json();
      Alert.alert('Data', JSON.stringify(data));
    } catch (error) {
      Alert.alert('Error', 'Failed to fetch data.');
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome!</Text>
      <Text style={styles.subtitle}>You are securely authenticated.</Text>

      <TouchableOpacity style={styles.dataButton} onPress={handleFetchProtectedData}>
        <Text style={styles.dataButtonText}>Fetch Protected Data</Text>
      </TouchableOpacity>

      <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
        <Text style={styles.logoutButtonText}>Sign Out</Text>
      </TouchableOpacity>
    </View>
  );
}

